import{_ as n,o as i,c as a,a4 as o}from"./chunks/framework.Br660gtV.js";const p=JSON.parse('{"title":"ADR-006: Informational perf bench + skippable ceiling","description":"","frontmatter":{},"headers":[],"relativePath":"reference/decisions/ADR-006-informational-perf-bench.md","filePath":"reference/decisions/ADR-006-informational-perf-bench.md"}'),r={name:"reference/decisions/ADR-006-informational-perf-bench.md"};function t(s,e,l,c,d,h){return i(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="adr-006-informational-perf-bench-skippable-ceiling" tabindex="-1">ADR-006: Informational perf bench + skippable ceiling <a class="header-anchor" href="#adr-006-informational-perf-bench-skippable-ceiling" aria-label="Permalink to &quot;ADR-006: Informational perf bench + skippable ceiling&quot;">â€‹</a></h1><blockquote><p><strong>Date</strong>: 2026-06-28 <strong>Status</strong>: Accepted <strong>Source</strong>: RD-10 (non-functional), resolving RD-09 DEF-4</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">â€‹</a></h2><p>RD-10 sets a frame-budget target: composing + diff-serializing a 200Ă—50 frame should have a median â‰¤ 16 ms. But wall-clock timing is environment-sensitive â€” CI runners are noisy and shared, and contributor machines vary widely. A hard timing gate in CI would flake; no timing check at all would let regressions slip.</p><h2 id="options-considered" tabindex="-1">Options Considered <a class="header-anchor" href="#options-considered" aria-label="Permalink to &quot;Options Considered&quot;">â€‹</a></h2><h3 id="option-a-hard-fail-the-16-ms-budget-in-ci" tabindex="-1">Option A: Hard-fail the 16 ms budget in CI <a class="header-anchor" href="#option-a-hard-fail-the-16-ms-budget-in-ci" aria-label="Permalink to &quot;Option A: Hard-fail the 16 ms budget in CI&quot;">â€‹</a></h3><ul><li><strong>Pros</strong>: Strongest enforcement.</li><li><strong>Cons</strong>: Flaky on shared/throttled runners; erodes trust in the suite.</li></ul><h3 id="option-b-regression-vs-stored-baseline-in-ci" tabindex="-1">Option B: Regression-vs-stored-baseline in CI <a class="header-anchor" href="#option-b-regression-vs-stored-baseline-in-ci" aria-label="Permalink to &quot;Option B: Regression-vs-stored-baseline in CI&quot;">â€‹</a></h3><ul><li><strong>Pros</strong>: Adapts to the runner.</li><li><strong>Cons</strong>: Needs a stored baseline + tuning; heavy for a foundation library.</li></ul><h3 id="option-c-informational-contended-runs-a-serial-ceiling-check" tabindex="-1">Option C: Informational contended runs + a serial ceiling check <a class="header-anchor" href="#option-c-informational-contended-runs-a-serial-ceiling-check" aria-label="Permalink to &quot;Option C: Informational contended runs + a serial ceiling check&quot;">â€‹</a></h3><ul><li><strong>Pros</strong>: Real assertion on capable dev hardware; CI and parallel verification record numbers informationally; an opt-out (<code>TUI_SKIP_PERF</code>) covers slow local machines.</li><li><strong>Cons</strong>: No hard CI gate on timing (accepted â€” timing is environment-sensitive).</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">â€‹</a></h2><p><strong>Chosen option</strong>: Option C â€” <code>npm run bench</code> prints median/p95 informationally. Performance specifications log under <code>CI</code>, Turbo task fan-out, or <code>TUI_SKIP_PERF</code>. <code>yarn perf:check</code> runs the budgets serially and enforces the 16 ms ceilings.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">â€‹</a></h2><p>This mirrors RD-09&#39;s stance: deterministic evidence (byte-proportionality, size-independence) is always asserted, while wall-clock timing stays informational under CI. A deliberate serial run on capable hardware is the real gate; contended runs track regressions without flaking. The detection-budget test follows the same skippable-timing rule. This resolves RD-09 DEF-4.</p><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">â€‹</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">â€‹</a></h3><ul><li>A real serial perf gate without CI or parallel-verification flakes; regression numbers are still tracked in contended runs.</li><li>Byte-proportionality / size-independence remain deterministic, always-on oracles.</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">â€‹</a></h3><ul><li>No hard CI failure purely on a timing regression (caught off-CI or by inspecting the informational numbers).</li></ul><h3 id="risks" tabindex="-1">Risks <a class="header-anchor" href="#risks" aria-label="Permalink to &quot;Risks&quot;">â€‹</a></h3><ul><li>A slow regression could pass unnoticed if no one runs <code>yarn perf:check</code>; <code>yarn gate</code> includes it so deliberate acceptance runs retain enforcement.</li></ul>',22)])])}const f=n(r,[["render",t]]);export{p as __pageData,f as default};
